lib/ai/generate-hpi.ts 파일 생성:

import { generateText } from '@/lib/ai/gemini-client';
import { GENERATE_HPI_SYSTEM_PROMPT } from '@/lib/ai/prompts/generate-hpi';
import type { StructuredCase } from '@/lib/ai/types';

export async function generateHpi(
  structuredCase: StructuredCase,
  rawInputs: Array<{ rawText: string; timeTag: string | null }>
): Promise<string> {
  // HPI 관련 입력만 필터링하여 프롬프트 집중도 향상
  const hpiInputs = structuredCase.inputs.filter(i => i.sections.includes('hpi'));

  // C.C. 특화 필드를 포함한 컨텍스트 구성
  const { inputs: _, ...ccSpecificFields } = structuredCase;

  const userPrompt = JSON.stringify({
    hpiInputs,
    ccSpecificFields,
    rawInputs
  }, null, 2);

  const result = await generateText(userPrompt, GENERATE_HPI_SYSTEM_PROMPT);
  if (!result) throw new Error('HPI 생성 실패: 빈 응답');
  return result;
}

scripts/ai-harness.ts에서 Stage 2 통합:
1. normalizeInputs 호출로 StructuredCase 획득 (Stage 1)
2. generateHpi(structuredCase, rawInputs) 호출
3. 출력 콘솔 출력
4. case-02.json의 expectedHpi와 나란히 출력하여 육안 비교

